// ─── Prepare Input: parse base resume into header + dynamic + static sections ───
const body = $json.body || $json;
const baseResume = body.baseResume || '';
const jobDescription = body.jobDescription || '';
const recipientEmail = body.recipientEmail || 'rvnegi786@gmail.com';
const companyName = body.companyName || 'the company';

// Section boundary detection
const DYNAMIC_SECTIONS = ['PROFESSIONAL SUMMARY', 'SUMMARY', 'TECHNICAL SKILLS', 'SKILLS', 'PROFESSIONAL EXPERIENCE', 'WORK EXPERIENCE', 'EXPERIENCE'];
const STATIC_SECTIONS  = ['PROJECTS', 'AWARDS', 'ACHIEVEMENTS', 'EDUCATION'];
const ALL_SECTIONS = [...DYNAMIC_SECTIONS, ...STATIC_SECTIONS];

function detectSection(line) {
  const u = line.trim().toUpperCase().replace(/[*#_]/g, '');
  return ALL_SECTIONS.find(s => u === s || u.startsWith(s)) || null;
}

const lines = baseResume.split('\n');
let headerLines = [];
let sections = {};
let currentSection = null;
let currentLines = [];
let headerDone = false;

for (const raw of lines) {
  const trimmed = raw.trim();
  if (!trimmed) { if (currentSection) currentLines.push(''); continue; }
  const sect = detectSection(trimmed);
  if (sect && trimmed.replace(/[*#_ ]/g,'').length < 50) {
    if (currentSection) sections[currentSection] = [...currentLines];
    else if (!headerDone) headerLines = [...currentLines];
    currentSection = sect;
    currentLines = [];
    headerDone = true;
  } else if (!headerDone) {
    currentLines.push(trimmed);
  } else {
    currentLines.push(raw.trim());
  }
}
if (currentSection) sections[currentSection] = [...currentLines];

const getSection = (...keys) => {
  for (const k of keys) {
    const found = Object.keys(sections).find(s => s.includes(k));
    if (found) return { key: found, lines: sections[found] };
  }
  return { key: null, lines: [] };
};

// Build the dynamic-only text to send to LLM
const dynamicSectionKeys = Object.keys(sections).filter(k => DYNAMIC_SECTIONS.includes(k));
let dynamicText = headerLines.join('\n') + '\n\n';
for (const k of dynamicSectionKeys) {
  dynamicText += k + '\n' + sections[k].join('\n') + '\n\n';
}

// Preserve static sections verbatim
const staticSections = {};
for (const k of STATIC_SECTIONS) {
  const found = getSection(k);
  if (found.key) staticSections[found.key] = found.lines;
}

return {
  jobDescription,
  baseResume,
  dynamicResumeText: dynamicText.trim(),
  staticSections: JSON.stringify(staticSections),
  headerLines: JSON.stringify(headerLines),
  recipientEmail,
  companyName
};

// ─── Reassemble: LLM dynamic sections + original static sections ───
function cleanText(t) {
  return (t || '')
    .replace(/```[a-z]*\n?/gi, '')
    .replace(/```/g, '')
    .replace(/^#+\s*/gm, '')
    .trim();
}

const llmOutput = cleanText($("Generate Tailored Resume").item.json.text || '');
const meta = $node["Prepare Input"].json;
const headerLines = JSON.parse(meta.headerLines || '[]');
const staticSections = JSON.parse(meta.staticSections || '{}');

// Build final resume text:
// Header + LLM output (dynamic) + static sections verbatim
let finalResume = headerLines.join('\n') + '\n\n';
finalResume += llmOutput + '\n\n';

// Append static sections in order
const ORDER = ['PROJECTS', 'AWARDS', 'ACHIEVEMENTS', 'EDUCATION'];
for (const key of ORDER) {
  const found = Object.keys(staticSections).find(k => k.includes(key));
  if (found && staticSections[found] && staticSections[found].length) {
    finalResume += found + '\n';
    finalResume += staticSections[found].join('\n') + '\n\n';
  }
}

const dateStr = new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
return {
  resumeText: finalResume.trim(),
  recipientEmail: meta.recipientEmail,
  companyName: meta.companyName,
  emailBody: `<p>Hi,</p><p>Your tailored resume for <strong>${meta.companyName}</strong> is attached.</p><p>Best of luck!</p>`,
  subject: `📄 Resume for ${meta.companyName} — ${dateStr}`
};

// ─── PDF Generator v3 — Accurate, Clean, Professional ───
const PDFDocument = require('pdfkit');
const meta = $node["Prepare Doc Content"].json;
const rawText = meta.resumeText || '';

const stripMd = s => String(s)
  .replace(/\*\*(.*?)\*\*/g, '$1')
  .replace(/\*(.*?)\*/g, '$1')
  .replace(/^[#]+\s*/gm, '')
  .trim();

const extractUrl = s => { const m = s.match(/https?:\/\/[^\s)]+/); return m ? m[0] : null; };

// ── Parse sections ──────────────────────────────────────
const SECTION_KEYS = [
  'PROFESSIONAL SUMMARY', 'SUMMARY',
  'TECHNICAL SKILLS', 'SKILLS',
  'PROFESSIONAL EXPERIENCE', 'WORK EXPERIENCE', 'EXPERIENCE',
  'PROJECTS', 'AWARDS', 'ACHIEVEMENTS', 'EDUCATION'
];

const lines = rawText.split('\n');
let headerLines = [];
let sections = {};
let currentSection = null;
let currentLines = [];
let headerDone = false;

for (const raw of lines) {
  const trimmed = raw.trim();
  if (!trimmed) { if (currentSection) currentLines.push(''); continue; }
  const clean = stripMd(trimmed);
  const upper = clean.toUpperCase();
  const matched = SECTION_KEYS.find(s => upper === s || upper.startsWith(s + ' ') || upper.startsWith(s + ':'));
  if (matched && clean.length < 50) {
    if (currentSection) sections[currentSection] = [...currentLines];
    else if (!headerDone) headerLines = [...currentLines];
    currentSection = matched;
    currentLines = [];
    headerDone = true;
  } else if (!headerDone) {
    currentLines.push(clean);
  } else {
    currentLines.push(raw.trim());
  }
}
if (currentSection) sections[currentSection] = [...currentLines];

const getSection = (...keys) => {
  for (const k of keys) {
    const found = Object.keys(sections).find(s => s.includes(k));
    if (found) return sections[found];
  }
  return [];
};

// ── Build PDF ────────────────────────────────────────────
const pdfBuffer = await new Promise((resolve, reject) => {
  const doc = new PDFDocument({
    size: 'A4',
    margins: { top: 30, bottom: 30, left: 40, right: 40 },
    autoFirstPage: true,
    bufferPages: true
  });
  const chunks = [];
  doc.on('data', c => chunks.push(c));
  doc.on('end', () => resolve(Buffer.concat(chunks)));
  doc.on('error', reject);

  const PW = doc.page.width;
  const ML = 40, MR = 40;
  const L = ML;
  const R = PW - MR;
  const CW = R - L;
  const BLACK = '#1a1a1a';
  const MUTED = '#555555';
  const BLUE  = '#1155CC';
  const RULE  = '#BBBBBB';

  // ── Section header ──
  const drawSectionHeader = (title) => {
    if (doc.y > 30) doc.moveDown(0.45);
    doc.font('Helvetica-Bold').fontSize(10.5).fillColor(BLACK)
       .text(title.toUpperCase(), L, doc.y, { width: CW });
    const ry = doc.y + 1.5;
    doc.moveTo(L, ry).lineTo(R, ry).lineWidth(0.6).strokeColor(RULE).stroke();
    doc.moveDown(0.3);
  };

  // ── Bullet line ──
  const drawBullet = (text) => {
    const clean = stripMd(text).replace(/^[-•*]\s*/, '').trim();
    if (!clean) return;
    doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
       .text('•  ' + clean, L + 8, doc.y, { width: CW - 8, lineGap: 1.5 });
    doc.moveDown(0.08);
  };

  // ── Two-column row (safe: snapshot y before both writes) ──
  const drawTwoCol = (leftStr, rightStr, opts = {}) => {
    const sy = doc.y;
    const lFont = opts.boldLeft ? 'Helvetica-Bold' : 'Helvetica';
    const lSize = opts.leftSize || 10;
    const rSize = opts.rightSize || 9;
    doc.font(lFont).fontSize(lSize).fillColor(BLACK)
       .text(stripMd(leftStr), L, sy, { width: 330, lineBreak: false });
    if (rightStr) {
      doc.font('Helvetica-Oblique').fontSize(rSize).fillColor(MUTED)
         .text(stripMd(rightStr), L, sy, { width: CW, align: 'right', lineBreak: false });
    }
    // advance past the taller of the two
    const approxH = Math.max(lSize, rSize) * 1.4;
    doc.y = sy + approxH;
    doc.moveDown(0.2);
  };

  // ═══════════════════════════════════════════════
  // HEADER
  // ═══════════════════════════════════════════════
  const name        = headerLines[0] || '';
  const contactLine = headerLines[1] || '';
  const linksLine   = headerLines[2] || '';
  const extraLine   = headerLines[3] || '';

  doc.font('Helvetica-Bold').fontSize(20).fillColor(BLACK)
     .text(name, L, doc.y, { align: 'center', width: CW });
  doc.moveDown(0.15);

  if (contactLine) {
    doc.font('Helvetica').fontSize(9.5).fillColor(MUTED)
       .text(contactLine, L, doc.y, { align: 'center', width: CW });
    doc.moveDown(0.1);
  }

  // links line — split on | or spaces, render each URL in blue
  const renderLinksLine = (line) => {
    if (!line) return;
    // Try to render entire line; if it contains a URL, make it blue
    const url = extractUrl(line);
    if (url) {
      doc.font('Helvetica').fontSize(9.5).fillColor(BLUE)
         .text(line, L, doc.y, { align: 'center', width: CW, link: url, underline: true });
    } else {
      doc.font('Helvetica').fontSize(9.5).fillColor(MUTED)
         .text(line, L, doc.y, { align: 'center', width: CW });
    }
    doc.moveDown(0.1);
  };
  renderLinksLine(linksLine);
  if (extraLine) renderLinksLine(extraLine);

  // Divider
  doc.moveDown(0.2);
  doc.moveTo(L, doc.y).lineTo(R, doc.y).lineWidth(1).strokeColor(BLACK).stroke();
  doc.moveDown(0.35);

  // ═══════════════════════════════════════════════
  // PROFESSIONAL SUMMARY
  // ═══════════════════════════════════════════════
  const summaryLines = getSection('SUMMARY');
  if (summaryLines.length) {
    drawSectionHeader('Professional Summary');
    const txt = summaryLines
      .map(l => stripMd(l).replace(/^[-•*]\s*/, '').trim())
      .filter(Boolean).join(' ');
    doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
       .text(txt, L, doc.y, { width: CW, lineGap: 2, align: 'justify' });
    doc.moveDown(0.15);
  }

  // ═══════════════════════════════════════════════
  // TECHNICAL SKILLS
  // ═══════════════════════════════════════════════
  const skillLines = getSection('SKILLS');
  if (skillLines.length) {
    drawSectionHeader('Technical Skills');
    skillLines.forEach(raw => {
      const clean = stripMd(raw).replace(/^[-•*]\s*/, '').trim();
      if (!clean) return;
      const ci = clean.indexOf(':');
      if (ci > -1) {
        const cat   = clean.slice(0, ci + 1).trim();
        const skills = clean.slice(ci + 1).trim();
        const sy = doc.y;
        doc.font('Helvetica-Bold').fontSize(9.5).fillColor(BLACK)
           .text(cat + ' ', L, sy, { continued: true, lineBreak: false });
        doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
           .text(skills, { lineGap: 1.5 });
      } else {
        doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
           .text(clean, L, doc.y, { width: CW, lineGap: 1.5 });
      }
      doc.moveDown(0.08);
    });
  }

  // ═══════════════════════════════════════════════
  // PROFESSIONAL EXPERIENCE
  // ═══════════════════════════════════════════════
  const expLines = getSection('EXPERIENCE');
  if (expLines.length) {
    drawSectionHeader('Professional Experience');
    expLines.forEach(raw => {
      const clean = stripMd(raw).replace(/\s+/g, ' ').trim();
      if (!clean) return;
      const isJobHeader =
        (clean.includes('|') || clean.includes('—')) &&
        (clean.match(/\d{4}/) || /present/i.test(clean));
      if (isJobHeader) {
        doc.moveDown(0.2);
        const parts = clean.split('|').map(p => p.trim());
        const datePart  = parts[parts.length - 1];
        const titleComp = parts.slice(0, -1).join(' | ');
        drawTwoCol(titleComp, datePart, { boldLeft: true, leftSize: 10, rightSize: 9 });
      } else {
        drawBullet(clean);
      }
    });
  }

  // ═══════════════════════════════════════════════
  // PROJECTS
  // ═══════════════════════════════════════════════
  const projLines = getSection('PROJECTS');
  if (projLines.length) {
    drawSectionHeader('Projects');
    let i = 0;
    while (i < projLines.length) {
      const raw   = projLines[i] || '';
      const clean = stripMd(raw).replace(/^[-•*]\s*/, '').trim();
      if (!clean) { i++; continue; }

      // A project title line has a separator (— or |) OR a URL OR is bold-style (no leading dash)
      const url = extractUrl(clean);
      const hasSep = /—|\s-\s/.test(clean);
      const isTitle = (url || hasSep) && !raw.trim().startsWith('-') && !raw.trim().startsWith('•');

      if (isTitle) {
        // Remove URL from display title
        const titleNoUrl = url ? clean.replace(url, '').replace(/\s*[|—]\s*$/, '').trim() : clean;
        const sy = doc.y;
        // Bold project name + tech stack
        doc.font('Helvetica-Bold').fontSize(10).fillColor(BLACK)
           .text('• ' + titleNoUrl, L, sy, { width: 310, lineBreak: false });
        // URL on the right in blue
        if (url) {
          const displayUrl = url.replace(/^https?:\/\//, '');
          doc.font('Helvetica').fontSize(9).fillColor(BLUE)
             .text(displayUrl, L, sy, {
               width: CW, align: 'right',
               link: url, underline: true,
               lineBreak: false
             });
        }
        doc.y = sy + 14;
        doc.moveDown(0.1);
        i++;
        // Description bullets immediately following
        while (i < projLines.length) {
          const sub = (projLines[i] || '').trim();
          if (!sub) { i++; break; }
          const isBullet = sub.startsWith('-') || sub.startsWith('•') || sub.startsWith('*');
          const isNewSection = SECTION_KEYS.find(k => sub.toUpperCase().replace(/[*#_]/g,'').startsWith(k));
          if (isNewSection) break;
          if (isBullet) { drawBullet(sub); i++; }
          else break;
        }
      } else {
        drawBullet(clean);
        i++;
      }
    }
  }

  // ═══════════════════════════════════════════════
  // AWARDS
  // ═══════════════════════════════════════════════
  const awardLines = getSection('AWARD', 'ACHIEVEMENT');
  if (awardLines.length) {
    drawSectionHeader('Awards & Recognition');
    awardLines.forEach(raw => {
      const clean = stripMd(raw).replace(/^[-•*]\s*/, '').trim();
      if (clean) drawBullet(clean);
    });
  }

  // ═══════════════════════════════════════════════
  // EDUCATION
  // ═══════════════════════════════════════════════
  const eduLines = getSection('EDUCATION');
  if (eduLines.length) {
    drawSectionHeader('Education');
    eduLines.forEach(raw => {
      const clean = stripMd(raw).replace(/^[-•*]\s*/, '').trim();
      if (!clean) return;
      // Lines with a date at the end: split into left + date
      const dateMatch = clean.match(/^(.+?)\s{2,}((?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec|\d{4}).+)$/) ||
                        clean.match(/^(.+?)\s+(\w{3}\s+\d{4}\s*[–-]\s*\w{3}\s+\d{4}.*)$/) ||
                        clean.match(/^(.+?)\s+(\w{3}\s+\d{4}\s*[–-]\s*\w{3}\s+\d{4})$/);
      if (dateMatch) {
        drawTwoCol(dateMatch[1], dateMatch[2], { boldLeft: true, leftSize: 10, rightSize: 9 });
      } else if (clean.includes('|')) {
        const parts = clean.split('|').map(p => p.trim());
        drawTwoCol(parts[0], parts[1] || '', { boldLeft: true, leftSize: 10, rightSize: 9 });
      } else {
        doc.font('Helvetica').fontSize(9.5).fillColor(BLACK)
           .text(clean, L, doc.y, { width: CW, lineGap: 1.5 });
        doc.moveDown(0.1);
      }
    });
  }

  doc.end();
});

return {
  json: {
    recipientEmail: meta.recipientEmail,
    subject: meta.subject,
    emailBody: meta.emailBody
  },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName: `Resume_${meta.companyName.replace(/\s+/g, '_')}.pdf`
    }
  }
};
